/**
 * Get exclusion frame at a given timestamp
 * @param timestamp - time in seconds
 * @param fps - frames per second (default 12)
 */
export function getDanceFrameAt(
  timestamp: number,
  fps: number = 12,
): VideoExclusionFrame | undefined {
  const frameIndex = Math.floor(timestamp * fps)
  return danceFrames.find(f => f.frameIndex === frameIndex) ?? danceFrames[0]
}